void segmentoConsecutivo(vector<int> v, int n, int &inicio, int &longitud) {
    int lonActual = 1, lonMax = 1;
    int inicioActual = 0;
    inicio = 0;
    for (int i = 1; i < n; i++) {
        if (v[i] == v[i-1] + 1) {
            lonActual++;
        } else {
            lonActual = 1;
            inicioActual = i;
        }
        if (lonActual > lonMax) {
            lonMax = lonActual;
            inicio = inicioActual;
        }
    }
    longitud = lonMax;
}
